@app.route('/api/invoices/<int:invoice_id>/download', methods=['GET'])
def download_invoice(invoice_id):
    # Construct the filename based on the invoice_id
    filename = f"invoice_{invoice_id}.pdf"
    filepath = os.path.join(INVOICE_DIR, filename)

    # Check if the file exists
    if not os.path.exists(filepath):
        # If the file does not exist, return a 404 Not Found error.
        # In a real application, you might also log this attempt.
        abort(404, description=f"Invoice {invoice_id} not found.")

    # In a real-world scenario, you would also verify
    # that the authenticated user is authorized to download this specific invoice.
    # For this problem, we assume authentication middleware has already verified the user
    # and we just need to serve the file if it exists.

    try:
        # Use send_file to serve the PDF.
        # as_attachment=True will prompt a download dialog in the browser.
        # The mimetype is set to 'application/pdf'.
        return send_file(
            filepath,
            mimetype='application/pdf',
            as_attachment=True,
            download_name=filename # Specify the name that appears in the download dialog
        )
    except Exception as e:
        # Catch any other potential errors during file sending
        app.logger.error(f"Error serving invoice {invoice_id}: {e}")
        abort(500, description="Could not process invoice download at this time.")

